+        TempServItemLine: Record "Service Item Line";
+        TempRepairStatus: Record "Repair Status";
+        HighestPriority: Integer;
+        HighestPriorityLineNo: Integer;
+    begin
+        if "Repair Status Code" = '' then
+            exit;
+
+        if not RepairStatus.Get("Repair Status Code") then
+            exit;
+
+        HighestPriority := RepairStatus.Priority;
+        HighestPriorityLineNo := "Line No.";
+
+        TempServItemLine.Reset();
+        TempServItemLine.SetRange("Document Type", "Document Type");
+        TempServItemLine.SetRange("Document No.", "Document No.");
+        TempServItemLine.SetFilter("Line No.", '<>%1', "Line No.");
+        TempServItemLine.SetFilter("Repair Status Code", '<>%1', '');
+        if TempServItemLine.FindSet() then
+            repeat
+                if TempRepairStatus.Get(TempServItemLine."Repair Status Code") then
+                    if TempRepairStatus.Priority < HighestPriority then begin
+                        HighestPriority := TempRepairStatus.Priority;
+                        HighestPriorityLineNo := TempServItemLine."Line No.";
+                    end;
+            until TempServItemLine.Next() = 0;
+
+        if "Line No." <> HighestPriorityLineNo then begin
+            TempServItemLine.Get("Document Type", "Document No.", HighestPriorityLineNo);
+            HighestPriorityRepairStatus.Get(TempServItemLine."Repair Status Code");
+        end else
+            HighestPriorityRepairStatus.Get("Repair Status Code");
+
+        ServHeader2.Get("Document Type", "Document No.");
+        ServHeader3 := ServHeader2;
+        if ServHeader2.Status <> HighestPriorityRepairStatus."Service Order Status" then begin
+            ServHeader2.SetValidatingFromLines(true);
+            if ServHeader2."Finishing Date" = 0D then
+                ServHeader2.Validate("Finishing Date", "Finishing Date");
+
+            OnUpdateServiceHeaderStatusOnBeforeValidateStatus(Rec, ServHeader2);
+
+            ServHeader2.Validate(Status, HighestPriorityRepairStatus."Service Order Status");
+            if not (ServHeader2.Status = ServHeader2.Status::Finished) then begin
+                ServHeader2."Finishing Date" := 0D;
+                ServHeader2."Finishing Time" := 0T;
+                ServHeader2."Service Time (Hours)" := 0;
+            end;
+            ServHeader2.UpdateServiceOrderChangeLog(ServHeader3);
+            ServHeader2.Modify();
+            if ServHeader2.Status = ServHeader2.Status::Finished then
+                UpdateStartFinishDateTime("Document Type", "Document No.", "Line No.", "Starting Date", "Starting Time",
+                  "Finishing Date", "Finishing Time", false);
+        end;
+    end;
+
